          type: 'boolean',
          description: 'exchange trading incentive'
        },
        image: {
          type: 'string',
          description: 'exchange image url'
        },
        name: {
          type: 'string',
          description: 'exchange name'
        },
        other_url_1: {
          type: 'string'
        },
        other_url_2: {
          type: 'string'
        },
